import numpy as np

def update_edge_distance(edge_distance, local_opt_tours, edge_n_used):
    # Parameters for penalizing and rewarding
    penalty_factor = 1.1
    reward_factor = 0.9
    max_uses = edge_n_used.max()

    # Create a copy of edge_distance to hold the updated values
    updated_edge_distance = np.copy(edge_distance)

    # Iterate over each edge and update the distance matrix based on the use frequency
    for i in range(edge_distance.shape[0]):
        for j in range(edge_distance.shape[1]):
            if i != j:
                usage = edge_n_used[i, j]

                # Penalize frequently used edges
                if usage > max_uses / 2:
                    updated_edge_distance[i, j] *= penalty_factor

                # Reward less used edges
                else:
                    updated_edge_distance[i, j] *= reward_factor

    return updated_edge_distance

import numpy as np

# {Increase the distance of heavily used edges and decrease the distance of rarely used edges to encourage exploring alternative routes.}
def update_edge_distance(edge_distance, local_opt_tours, edge_n_used):
    updated_edge_distance = edge_distance.copy()
    max_usage = np.max(edge_n_used)
    min_usage = np.min(edge_n_used[edge_n_used > 0]) if np.any(edge_n_used > 0) else 1

    rows, cols = edge_n_used.shape
    for i in range(rows):
        for j in range(cols):
            if i != j:
                usage_ratio = (edge_n_used[i, j] - min_usage) / (max_usage - min_usage + 1e-9)
                # Increase the edge weight for heavily used edges
                updated_edge_distance[i, j] += updated_edge_distance[i, j] * usage_ratio
                # Decrease the edge weight for rarely used edges
                updated_edge_distance[i, j] -= updated_edge_distance[i, j] * (1 - usage_ratio)

    return updated_edge_distance
